import React, { useState, useEffect } from 'react';
import api from '../services/api';

function Relatorios() {
    const [filtros, setFiltros] = useState({ cliente_id: '', data_inicio: '', data_fim: '', categoria_id: '' });
    const [mostrarTempo, setMostrarTempo] = useState(false);
    const [resultados, setResultados] = useState([]);
    const [clientes, setClientes] = useState([]);
    const [categorias, setCategorias] = useState([]);

    useEffect(() => {
        const load = async () => {
            const [cli, cat] = await Promise.all([api.get('/clientes'), api.get('/categorias')]);
            setClientes(cli.data);
            setCategorias(cat.data);
        };
        load();
    }, []);

    const gerar = async () => {
        const params = { ...filtros, mostrar_tempo: mostrarTempo };
        const res = await api.get('/relatorios', { params });
        setResultados(res.data.dados);
    };

    return (
        <div>
            <h2>Relatórios</h2>
            <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap', marginBottom: '20px' }}>
                <select onChange={e => setFiltros({...filtros, cliente_id: e.target.value})}><option value="">Todos clientes</option>{clientes.map(c => <option key={c.id} value={c.id}>{c.nome}</option>)}</select>
                <input type="date" onChange={e => setFiltros({...filtros, data_inicio: e.target.value})} />
                <input type="date" onChange={e => setFiltros({...filtros, data_fim: e.target.value})} />
                <select onChange={e => setFiltros({...filtros, categoria_id: e.target.value})}><option value="">Todos serviços</option>{categorias.map(c => <option key={c.id} value={c.id}>{c.nome}</option>)}</select>
                <label><input type="checkbox" checked={mostrarTempo} onChange={e => setMostrarTempo(e.target.checked)} /> Mostrar tempo</label>
                <button onClick={gerar}>Gerar</button>
            </div>
            <table border="1" cellPadding="8" style={{ width: '100%', borderCollapse: 'collapse' }}>
                <thead><tr><th>Cliente</th><th>Data</th><th>Equipamento</th><th>Serviço</th><th>Tipo</th><th>Valor</th>{mostrarTempo && <th>Tempo</th>}</tr></thead>
                <tbody>
                    {resultados.map(os => (
                        <tr key={os.id}>
                            <td>{os.cliente_nome}</td><td>{os.data_conclusao}</td><td>{os.equipamento}</td><td>{os.servico_realizado}</td><td>{os.tipo_atendimento}</td><td>R$ {parseFloat(os.preco_final).toFixed(2)}</td>
                            {mostrarTempo && <td>{Math.floor(os.tempo_acumulado_segundos / 60)} min</td>}
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
}

export default Relatorios;
